module adder_16bit
(
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);

    wire [15:0] carry;
    wire [7:0] sum1, sum2;
    wire cout1, cout2;
    assign {carry[7], sum1} = a[7:0] + b[7:0] + Cin;
    assign {carry[15], sum2} = a[15:8] + b[15:8] + carry[7];
    assign y = {sum2, sum1};
    assign Co = carry[15];
endmodule
